mapper.select:
SELECT main.UTLINSTT_ID , main.RGSN_TS , main.AMNN_TS , main.AMNN_USER_ID , eim.ETNM AS CMPN_NM , CASE WHEN eim.BZN IS NULL THEN '' ELSE REGEXP_REPLACE(eim.BZN, '^([0-9]{3})-?([0-9]{2})-?([0-9]{5})$', '\1-\2-\3') END AS BZN , (SELECT CASE WHEN count(*) = 0 THEN 'N' ELSE 'Y' END from IVBADM.TB_BOX_IVT_INVSTMNT_INFO_R) as fncnYn , main.INVM_CNVS_STTS FROM TB_BOX_IVT_INVM_CNVRS_RQST_INFO_M main LEFT JOIN ( SELECT UTLINSTT_ID, MIN(AMNN_TS) AS FIRST_ACCEPT_DATE FROM IVBADM.TB_BOX_IVT_VNCM_CPTL_H WHERE USE_YN = 'Y' GROUP BY UTLINSTT_ID ) first_dt ON first_dt.UTLINSTT_ID = main.UTLINSTT_ID LEFT JOIN ( SELECT UTLINSTT_ID, MAX(AMNN_TS) AS LAST_CONVERT_DATE FROM IVBADM.TB_BOX_IVT_VNCM_CPTL_H GROUP BY UTLINSTT_ID ) last_dt ON last_dt.UTLINSTT_ID = main.UTLINSTT_ID INNER JOIN IVBADM.TB_BOX_IVT_ENPR_INFO_M eim ON main.UTLINSTT_ID = eim.UTLINSTT_ID WHERE 1=1
AND main.INVM_CNVS_STTS = #{dsnc}
AND eim.ETNM LIKE '%'||#{cmpnNm}||'%'
AND main.BZN = #{bzn}
AND main.UTLINSTT_ID = #{utlinsttId}
ORDER BY main.RGSN_TS DESC

SELECT main.UTLINSTT_ID , main.DSNC , main.INPI_ITM , main.RGSR_ID , main.RGSN_TS -- , TO_CHAR(TO_DATE(main.RGSN_TS,'YYYYMMDD'),'YYYYMMDD') AS RGSN_TS , main.CMPN_NM , main.RGSR_NM , CASE WHEN main.BZN IS NULL THEN '' ELSE REGEXP_REPLACE(main.BZN, '^([0-9]{3})-?([0-9]{2})-?([0-9]{5})$', '\1-\2-\3') END AS BZN FROM TB_BOX_IVT_ETC_INPT_ITM_MNGM_R main WHERE 1=1
AND main.CMPN_NM LIKE '%'||#{cmpnNm}||'%'
AND main.BZN = #{bzn}
AND main.DSNC = #{dsnc}
ORDER BY main.RGSN_TS DESC

