UPDATE
    TB_BOX_IVT_VNCM_CPTL_L
SET
    USE_YN = #{useYn}
    , AMNN_USER_ID = #{amnnUserId}
    , AMNN_TS = CURRENT_TIMESTAMP
WHERE
    UTLINSTT_ID=#{utlinsttId}

UPDATE
TB_BOX_IVT_INVM_CNVS_L
SET
CNVS_RQST_STTS_CD_ID = #{cnvsRqstSttsCdId}
, AMNN_USER_ID = #{amnnUserId}
, AMNN_TS = CURRENT_TIMESTAMP
WHERE
UTLINSTT_ID = #{utlinsttId} AND CNVS_RQST_SQN = #{cnvsRqstSqn}

UPDATE
TB_BOX_IVT_INVM_CNVRS_RQST_INFO_M
SET
  INVM_CNVS_STTS = #{dsnc}
, AMNN_USER_ID = #{amnnUserId}
, AMNN_TS = CURRENT_TIMESTAMP
WHERE
UTLINSTT_ID = #{utlinsttId}

UPDATE
TB_BOX_IVT_CNSG_REQS_M
SET
CNSG_STTS_CD    = #{CONSULT_CANCEL_CODE}
, AMNN_USER_ID  = #{amnnUserId}
, AMNN_TS = CURRENT_TIMESTAMP
WHERE
REQS_INTT_ID = #{reqsInttId} AND CNSG_STTS_CD = #{CONSULT_STANDBY_CODE}

UPDATE
TB_BOX_IVT_INQR_SBJC_M
SET
PGST_CD = #{QA_CANCEL_CODE}


WHERE
RGSR_USIS_ID = #{rgsrUsisId} AND PGST_CD = #{QA_STANDBY_CODE}

